import os
import secrets
from flask import Flask, redirect, request, session, url_for, jsonify
import requests

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# OAuth 2.0 Configuration
OAUTH_CLIENT_ID = os.environ.get('OAUTH_CLIENT_ID', 'your_client_id')
OAUTH_CLIENT_SECRET = os.environ.get('OAUTH_CLIENT_SECRET', 'your_client_secret')
OAUTH_AUTHORIZATION_URL = os.environ.get('OAUTH_AUTHORIZATION_URL', 'https://oauth-provider.com/authorize')
OAUTH_TOKEN_URL = os.environ.get('OAUTH_TOKEN_URL', 'https://oauth-provider.com/token')
OAUTH_REDIRECT_URI = os.environ.get('OAUTH_REDIRECT_URI', 'http://localhost:5000/callback')
OAUTH_SCOPE = os.environ.get('OAUTH_SCOPE', 'read write')


@app.route('/')
def index():
    if 'access_token' in session:
        return jsonify({
            'message': 'You are logged in',
            'access_token': session['access_token'][:10] + '...'
        })
    return jsonify({'message': 'Welcome! Please login', 'login_url': url_for('login', _external=True)})


@app.route('/login')
def login():
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    
    authorization_params = {
        'client_id': OAUTH_CLIENT_ID,
        'redirect_uri': OAUTH_REDIRECT_URI,
        'response_type': 'code',
        'scope': OAUTH_SCOPE,
        'state': state
    }
    
    authorization_url = f"{OAUTH_AUTHORIZATION_URL}?"
    authorization_url += '&'.join([f"{key}={value}" for key, value in authorization_params.items()])
    
    return redirect(authorization_url)


@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({'error': error, 'error_description': request.args.get('error_description')}), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return jsonify({'error': 'Missing authorization code'}), 400
    
    if not state:
        return jsonify({'error': 'Missing state parameter'}), 400
    
    stored_state = session.get('oauth_state')
    if not stored_state:
        return jsonify({'error': 'No state found in session'}), 400
    
    if not secrets.compare_digest(state, stored_state):
        return jsonify({'error': 'Invalid state parameter - possible CSRF attack'}), 400
    
    session.pop('oauth_state', None)
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OAUTH_REDIRECT_URI,
        'client_id': OAUTH_CLIENT_ID,
        'client_secret': OAUTH_CLIENT_SECRET
    }
    
    try:
        response = requests.post(
            OAUTH_TOKEN_URL,
            data=token_data,
            headers={'Accept': 'application/json'},
            timeout=10
        )
        
        if response.status_code != 200:
            return jsonify({
                'error': 'Token exchange failed',
                'status_code': response.status_code,
                'response': response.text
            }), 400
        
        token_response = response.json()
        access_token = token_response.get('access_token')
        
        if not access_token:
            return jsonify({'error': 'No access token in response'}), 400
        
        session['access_token'] = access_token
        
        if 'refresh_token' in token_response:
            session['refresh_token'] = token_response['refresh_token']
        
        if 'expires_in' in token_response:
            session['token_expires_in'] = token_response['expires_in']
        
        return redirect(url_for('index'))
    
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Request failed', 'details': str(e)}), 500


@app.route('/logout')
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})


@app.route('/protected')
def protected():
    access_token = session.get('access_token')
    if not access_token:
        return jsonify({'error': 'Not authenticated'}), 401
    
    return jsonify({
        'message': 'This is a protected resource',
        'access_token': access_token[:10] + '...'
    })


if __name__ == '__main__':
    app.run(debug=True, port=5000)